<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Falling Sand Cellular Automata Sandbox</title>
    <style>
        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background-color: #1e1e2f; /* Dark background */
            color: #e0e0ff;
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 20px;
        }

        h1 {
            color: #a8dadc;
            margin-bottom: 10px;
        }

        #controls {
            display: flex;
            flex-wrap: wrap;
            gap: 10px;
            justify-content: center;
            margin-bottom: 20px;
            padding: 15px;
            background-color: #2a2a40;
            border-radius: 8px;
            box-shadow: 0 4px 6px rgba(0, 0, 0, 0.3);
        }

        /* Material Buttons Styling (Material Design inspired) */
        button {
            padding: 12px 18px;
            border: none;
            border-radius: 6px;
            cursor: pointer;
            font-weight: bold;
            transition: background-color 0.2s, transform 0.1s;
            box-shadow: 0 3px #1a1a25; /* Depth effect */
        }

        button:active {
            transform: translateY(2px);
            box-shadow: 0 1px #1a1a25;
        }

        .material-btn {
            background-color: #3c3c60;
            color: white;
        }

        #clear {
            background-color: #d9534f; /* Red for danger */
            box-shadow: 0 3px #b83e47;
            margin-left: 20px;
        }
        #clear:active {
             box-shadow: 0 1px #b83e47;
        }

        /* Canvas Container */
        #canvas-container {
            border: 5px solid #a8dadc;
            background-color: #0d0d18; /* Very dark internal background */
            box-shadow: 0 10px 20px rgba(0, 0, 0, 0.5);
        }

        #sand {
            display: block;
            cursor: crosshair;
        }

    </style>
</head>
<body>

    <h1>Falling Sand Sandbox</h1>

    <div id="controls">
        <!-- Material Selectors -->
        <button class="material-btn" id="mat-sand" data-material="sand">Sand</button>
        <button class="material-btn" id="mat-water" data-material="water">Water</button>
        <button class="material-btn" id="mat-wall" data-material="wall">Wall</button>
        <button class="material-btn" id="mat-acid" data-material="acid">Acid</button>
        <button class="material-btn" id="mat-empty" data-material="empty">Eraser (Empty)</button>

        <!-- Clear Button -->
        <button id="clear">Clear Grid</button>
    </div>

    <div id="canvas-container">
        <canvas id="sand"></canvas>
    </div>

    <script>
        // --- Configuration Constants ---
        const GRID_W = 100; // Width in cells (must be >= 80)
        const GRID_H = 100; // Height in cells (must be >= 80)
        const CELL_SIZE = 6; // CSS pixels per cell

        // Material definitions and colors for rendering
        const MATERIALS = {
            'empty': { color: '#0d0d18', char: ' ' },
            'sand': { color: '#e9c46a', char: 'S' },
            'water': { color: '#2a9d8f', char: '~' },
            'wall': { color: '#5c7c63', char: '#' },
            'acid': { color: '#ff6b6b', char: 'A' }
        };

        // --- Global State ---
        let grid = [];
        let selectedMaterial = 'sand';

        // --- Canvas Setup ---
        const canvas = document.getElementById('sand');
        const ctx = canvas.getContext('2d');

        canvas.width = GRID_W * CELL_SIZE;
        canvas.height = GRID_H * CELL_SIZE;

        /**
         * Initializes the grid state (the 2D array).
         */
        function initializeGrid() {
            grid = [];
            for (let y = 0; y < GRID_H; y++) {
                grid[y] = new Array(GRID_W).fill('empty');
            }
        }

        /**
         * Renders the entire grid state to the canvas.
         */
        function render() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            for (let y = 0; y < GRID_H; y++) {
                for (let x = 0; x < GRID_W; x++) {
                    const material = grid[y][x];
                    const color = MATERIALS[material].color;

                    ctx.fillStyle = color;
                    ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);

                    // Optional: Draw a slight border for visibility (helps debugging)
                    ctx.strokeStyle = '#1a1a25';
                    ctx.strokeRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
                }
            }
        }

        // --- Simulation API Implementation ---
        window.sim = {
            w: GRID_W,
            h: GRID_H,

            /**
             * Gets the material at (x, y).
             * @param {number} x - Column index.
             * @param {number} y - Row index.
             * @returns {string} Material name ("empty", "sand", etc.).
             */
            get: function(x, y) {
                if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) return 'empty';
                return grid[y][x];
            },

            /**
             * Sets the material at (x, y).
             * @param {number} x - Column index.
             * @param {number} y - Row index.
             * @param {string} material - Material name.
             */
            set: function(x, y, material) {
                if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) return;
                grid[y][x] = material;
                render(); // Re-render immediately upon programmatic set
            },

            /**
             * Empties the whole grid.
             */
            clear: function() {
                for (let y = 0; y < GRID_H; y++) {
                    for (let x = 0; x < GRID_W; x++) {
                        grid[y][x] = 'empty';
                    }
                }
                render();
            },

            /**
             * Advances the simulation by n steps synchronously.
             * @param {number} n - Number of ticks to run.
             */
            tick: function(n) {
                for (let i = 0; i < n; i++) {
                    this._step();
                }
                render();
            },

            /**
             * Internal step function: Processes movement bottom-up.
             * This is the core simulation logic.
             */
            _step: function() {
                // We must process from the second to last row (H-2) up to the top (0).
                // The bottom row (H-1) cannot fall further.
                for (let y = GRID_H - 2; y >= 0; y--) {
                    for (let x = 0; x < GRID_W; x++) {
                        const currentMaterial = grid[y][x];

                        if (currentMaterial === 'empty' || currentMaterial === 'wall') {
                            continue; // Walls don't move, empty space does nothing.
                        }

                        // Check if the particle has already moved this step (to prevent double movement)
                        // We use a temporary storage mechanism for moves to ensure atomicity per tick.
                        if (!this._processParticle(x, y, currentMaterial)) {
                            // If _processParticle returns false, it means the material was handled/moved.
                            // Since we are iterating bottom-up, if it moved, its old spot is now 'empty' 
                            // and its new spot is filled by the movement logic itself.
                        }
                    }
                }
            }
        };

        /**
         * Handles the movement of a single particle at (x, y).
         * Returns true if the particle moved/was processed, false otherwise.
         */
        sim._processParticle = function(startX, startY, material) {
            let targetX = startX;
            let targetY = startY;

            // 1. Handle Sand Movement
            if (material === 'sand') {
                const nextY = startY + 1;
                const belowMaterial = this.get(startX, nextY);

                if (belowMaterial === 'empty' || belowMaterial === 'water' || belowMaterial === 'acid') {
                    // Falls straight down
                    targetX = startX;
                    targetY = nextY;
                } else if (belowMaterial !== 'wall') {
                    // Blocked, try diagonal slide
                    const directions = [
                        { dx: -1, dy: 0 }, // Down-Left check
                        { dx: 1, dy: 0 }   // Down-Right check
                    ];

                    // Randomize direction checking order for consistency
                    directions.sort(() => Math.random() - 0.5);

                    for (const dir of directions) {
                        const nextX = startX + dir.dx;
                        const nextY = startY + 1; // Always one step down

                        if (nextX >= 0 && nextX < GRID_W && nextY < GRID_H) {
                            const targetMaterial = this.get(nextX, nextY);
                            // Can slide if the spot is empty or liquid (water/acid)
                            if (targetMaterial === 'empty' || ['water', 'acid'].includes(targetMaterial)) {
                                targetX = nextX;
                                targetY = nextY;
                                break; // Found a path, stop checking directions
                            }
                        }
                    }
                }
            } 
            // 2. Handle Water Movement
            else if (material === 'water') {
                const nextY = startY + 1;
                const belowMaterial = this.get(startX, nextY);

                if (belowMaterial === 'empty' || ['sand', 'acid'].includes(belowMaterial)) {
                    // Falls straight down or into sand/acid pool
                    targetX = startX;
                    targetY = nextY;
                } else if (belowMaterial !== 'wall') {
                    // Blocked, spread horizontally
                    const directions = [
                        { dx: -1 }, // Left
                        { dx: 1 }   // Right
                    ];

                    directions.sort(() => Math.random() - 0.5);

                    for (const dir of directions) {
                        const nextX = startX + dir.dx;
                        if (nextX >= 0 && nextX < GRID_W) {
                            // Check if the spot below is empty or liquid, allowing spread
                            const targetMaterialBelow = this.get(nextX, startY + 1);

                            if (targetMaterialBelow === 'empty' || ['sand', 'acid'].includes(targetMaterialBelow)) {
                                // Found a path to spread
                                targetX = nextX;
                                targetY = startY; // Stays on the same row for horizontal movement
                                break; 
                            }
                        }
                    }
                }
            }
            // 3. Handle Acid Movement (Combines liquid fall/spread + dissolution)
            else if (material === 'acid') {
                let moved = false;

                // A. Try falling straight down (like water)
                const nextY = startY + 1;
                if (nextY < GRID_H && this.get(startX, nextY) !== 'wall') {
                    targetX = startX;
                    targetY = nextY;
                    moved = true;
                } else {
                    // B. Try spreading horizontally (like water)
                    const directions = [
                        { dx: -1 }, 
                        { dx: 1 }   
                    ];

                    directions.sort(() => Math.random() - 0.5);

                    for (const dir of directions) {
                        const nextX = startX + dir.dx;
                        if (nextX >= 0 && nextX < GRID_W) {
                            // Check if the spot below is empty or liquid, allowing spread
                            const targetMaterialBelow = this.get(nextX, startY + 1);

                            if (targetMaterialBelow === 'empty' || ['sand', 'acid'].includes(targetMaterialBelow)) {
                                // Found a path to spread
                                targetX = nextX;
                                targetY = startY;
                                moved = true;
                                break;
                            }
                        }
                    }
                }

                // C. Dissolution Check (Check neighbors below and beside the *original* position)
                // We check 3x3 area around (startX, startY) for targets:
                const dissolutionTargets = [
                    { x: startX - 1, y: startY + 1 }, // Left-Down
                    { x: startX, y: startY + 1 },     // Down
                    { x: startX + 1, y: startY + 1 }  // Right-Down
                ];

                for (const { x, y } of dissolutionTargets) {
                    if (x >= 0 && x < GRID_W && y >= 0 && y < GRID_H) {
                        const targetMaterial = this.get(x, y);
                        if (targetMaterial === 'sand' || targetMaterial === 'wall') {
                            // Acid dissolves the target material and itself (the acid moves into the spot).
                            // Since we are processing bottom-up, if dissolution happens, 
                            // the particle at (startX, startY) is considered to have moved/disappeared.
                            this.set(x, y, 'empty'); // Dissolve target
                        }
                    }
                }

            }


            // --- Execute Movement ---
            if (targetX !== startX || targetY !== startY) {
                // 1. Clear original spot
                this.set(startX, startY, 'empty');

                // 2. Place particle in new spot
                this.set(targetX, targetY, material);

                return true; // Particle moved
            } else if (material === 'acid') {
                 // If acid didn't move but dissolved something, we still count it as processed.
                 // Note: The dissolution happens via `this.set` calls above, which re-render.
                 return true; 
            }

            return false; // Particle remained in place or was blocked/static (walls)
        };


        // --- Event Handlers and Initialization ---

        /**
         * Handles painting on the canvas based on mouse position.
         */
        function handlePainting(event) {
            const rect = canvas.getBoundingClientRect();
            const scaleX = canvas.width / rect.width;
            const scaleY = canvas.height / rect.height;

            // Calculate coordinates relative to the internal grid size (GRID_W, GRID_H)
            const clientX = event.clientX - rect.left;
            const clientY = event.clientY - rect.top;

            const x = Math.floor((clientX * scaleX) / CELL_SIZE);
            const y = Math.floor((clientY * scaleY) / CELL_SIZE);

            if (x >= 0 && x < GRID_W && y >= 0 && y < GRID_H) {
                sim.set(x, y, selectedMaterial);
            }
        }

        // Setup listeners
        document.getElementById('sand').addEventListener('mousedown', (e) => {
            handlePainting(e);
        });
        document.getElementById('sand').addEventListener('mousemove', (e) => {
            if (e.buttons === 1) { // Left click held down
                handlePainting(e);
            }
        });
        // Prevent context menu on right-click, useful for drag painting
        canvas.addEventListener('contextmenu', e => e.preventDefault());


        document.querySelectorAll('.material-btn').forEach(button => {
            button.addEventListener('click', (e) => {
                selectedMaterial = e.currentTarget.dataset.material;
                console.log(`Selected material: ${selectedMaterial}`);
            });
        });

        document.getElementById('clear').addEventListener('click', () => {
            if (confirm("Are you sure you want to clear the entire grid?")) {
                sim.clear();
            }
        });


        // --- Main Loop and Initialization Call ---
        function gameLoop() {
            // Run one tick per frame for smooth animation
            sim.tick(1); 
            requestAnimationFrame(gameLoop);
        }

        window.onload = () => {
            initializeGrid();
            render(); // Initial render of empty grid
            gameLoop(); // Start the continuous simulation loop
        };

    </script>
</body>
</html>
